## 2️⃣ التخزين السحابي المتقدم (Cloud Storage - AWS S3 / Cloudinary)

### ملف الإعدادات `lib/storage.ts`

```typescript
import { S3Client, PutObjectCommand, DeleteObjectCommand } from "@aws-sdk/client-s3";
import { getSignedUrl } from "@aws-sdk/s3-request-presigner";
import { v4 as uuidv4 } from 'uuid';

// إعداد عميل S3
const s3Client = new S3Client({
  region: process.env.AWS_REGION || 'us-east-1',
  credentials: {
    accessKeyId: process.env.AWS_ACCESS_KEY_ID || '',
    secretAccessKey: process.env.AWS_SECRET_ACCESS_KEY || '',
  },
});

const BUCKET_NAME = process.env.AWS_BUCKET_NAME || '';

// رفع ملف
export async function uploadFile(file: File, folder: string = 'uploads') {
  try {
    const fileExt = file.name.split('.').pop();
    const fileName = `${folder}/${uuidv4()}.${fileExt}`;

    const buffer = Buffer.from(await file.arrayBuffer());

    const command = new PutObjectCommand({
      Bucket: BUCKET_NAME,
      Key: fileName,
      Body: buffer,
      ContentType: file.type,
      ACL: 'public-read',
    });

    await s3Client.send(command);

    const url = `https://${BUCKET_NAME}.s3.${process.env.AWS_REGION}.amazonaws.com/${fileName}`;

    return {
      success: true,
      url,
      fileName,
      size: file.size,
      type: file.type,
    };
  } catch (error) {
    console.error('Upload failed:', error);
    return { success: false, error };
  }
}

// حذف ملف
export async function deleteFile(fileName: string) {
  try {
    const command = new DeleteObjectCommand({
      Bucket: BUCKET_NAME,
      Key: fileName,
    });

    await s3Client.send(command);
    return { success: true };
  } catch (error) {
    console.error('Delete failed:', error);
    return { success: false, error };
  }
}

// إنشاء رابط موقع مؤقت للرفع المباشر من المتصفح
export async function getPresignedUploadUrl(fileName: string, fileType: string) {
  try {
    const command = new PutObjectCommand({
      Bucket: BUCKET_NAME,
      Key: `uploads/${uuidv4()}-${fileName}`,
      ContentType: fileType,
    });

    const url = await getSignedUrl(s3Client, command, { expiresIn: 3600 });
    return { success: true, url };
  } catch (error) {
    return { success: false, error };
  }
}

// تحسين الصور (باستخدام Cloudinary كبديل)
export async function optimizeImage(file: File) {
  // يمكن دمج Cloudinary هنا للتحسين التلقائي
  const formData = new FormData();
  formData.append('file', file);
  formData.append('upload_preset', process.env.CLOUDINARY_UPLOAD_PRESET || '');

  const response = await fetch(
    `https://api.cloudinary.com/v1_1/${process.env.CLOUDINARY_CLOUD_NAME}/image/upload`,
    {
      method: 'POST',
      body: formData,
    }
  );

  const data = await response.json();
  return {
    success: true,
    url: data.secure_url,
    publicId: data.public_id,
    width: data.width,
    height: data.height,
  };
}
