## 5️⃣ البحث المتقدم (Advanced Search)

### محرك البحث `lib/search.ts`

```typescript
import Post from "@/models/Post";
import { connectToDatabase } from "./mongodb";

interface SearchOptions {
  query: string;
  category?: string;
  tags?: string[];
  author?: string;
  dateFrom?: Date;
  dateTo?: Date;
  page?: number;
  limit?: number;
  sortBy?: 'relevance' | 'date' | 'views' | 'popular';
}

export async function advancedSearch(options: SearchOptions) {
  await connectToDatabase();

  const {
    query,
    category,
    tags,
    author,
    dateFrom,
    dateTo,
    page = 1,
    limit = 10,
    sortBy = 'relevance',
  } = options;

  const skip = (page - 1) * limit;

  // بناء استعلام البحث
  const searchQuery: any = { published: true };

  if (query) {
    searchQuery.$text = { $search: query };
  }

  if (category) {
    searchQuery.category = category;
  }

  if (tags && tags.length > 0) {
    searchQuery.tags = { $in: tags };
  }

  if (author) {
    searchQuery.author = author;
  }

  if (dateFrom || dateTo) {
    searchQuery.createdAt = {};
    if (dateFrom) searchQuery.createdAt.$gte = dateFrom;
    if (dateTo) searchQuery.createdAt.$lte = dateTo;
  }

  // ترتيب النتائج
  let sortOptions: any = {};
  switch (sortBy) {
    case 'date':
      sortOptions = { createdAt: -1 };
      break;
    case 'views':
      sortOptions = { views: -1 };
      break;
    case 'popular':
      sortOptions = { views: -1, 'comments.length': -1 };
      break;
    case 'relevance':
    default:
      sortOptions = { score: { $meta: "textScore" } };
      break;
  }

  const [posts, total] = await Promise.all([
    Post.find(searchQuery)
      .sort(sortOptions)
      .skip(skip)
      .limit(limit)
      .populate('author', 'name image')
      .lean(),
    Post.countDocuments(searchQuery),
  ]);

  return {
    posts,
    total,
    page,
    totalPages: Math.ceil(total / limit),
    hasMore: skip + posts.length < total,
  };
}

// اقتراحات البحث
export async function getSearchSuggestions(query: string, limit = 5) {
  await connectToDatabase();

  const suggestions = await Post.aggregate([
    {
      $match: {
        published: true,
        title: { $regex: query, $options: 'i' },
      },
    },
    { $sort: { views: -1 } },
    { $limit: limit },
    { $project: { title: 1, category: 1 } },
  ]);

  return suggestions;
}
```

### مكون البحث `components/SearchBar.tsx`

```tsx
"use client";
import { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import { Search, X, Clock, TrendingUp } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { getSearchSuggestions } from "@/app/actions/search";

export default function SearchBar() {
  const [query, setQuery] = useState("");
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isSearching, setIsSearching] = useState(false);
  const router = useRouter();
  const searchRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const fetchSuggestions = async () => {
      if (query.length < 2) {
        setSuggestions([]);
        return;
      }

      setIsSearching(true);
      try {
        const results = await getSearchSuggestions(query);
        setSuggestions(results);
        setShowSuggestions(true);
      } catch (error) {
        console.error('Failed to fetch suggestions:', error);
      } finally {
        setIsSearching(false);
      }
    };

    const debounceTimer = setTimeout(fetchSuggestions, 300);
    return () => clearTimeout(debounceTimer);
  }, [query]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim()) {
      router.push(`/search?q=${encodeURIComponent(query)}`);
      setShowSuggestions(false);
    }
  };

  const handleSuggestionClick = (title: string) => {
    router.push(`/search?q=${encodeURIComponent(title)}`);
    setShowSuggestions(false);
  };

  const clearSearch = () => {
    setQuery("");
    setSuggestions([]);
    setShowSuggestions(false);
  };

  return (
    <div ref={searchRef} className="relative w-full max-w-2xl">
      <form onSubmit={handleSubmit} className="relative">
        <Search className="absolute right-4 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
        <Input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          onFocus={() => query.length >= 2 && setShowSuggestions(true)}
          placeholder="ابحث عن مقالات..."
          className="pr-12 pl-10 h-12 text-lg"
        />
        {query && (
          <button
            type="button"
            onClick={clearSearch}
            className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
          >
            <X className="h-5 w-5" />
          </button>
        )}
        <Button 
          type="submit" 
          className="absolute left-2 top-1/2 -translate-y-1/2 h-8"
          disabled={!query.trim()}
        >
          بحث
        </Button>
      </form>

      {/* قائمة الاقتراحات */}
      {showSuggestions && suggestions.length > 0 && (
        <div className="absolute top-full mt-2 w-full bg-white rounded-lg shadow-lg border overflow-hidden z-50">
          <div className="p-2">
            <div className="text-xs font-semibold text-gray-500 px-3 py-2 flex items-center gap-2">
              <Clock className="h-3 w-3" />
              اقتراحات البحث
            </div>
            {suggestions.map((suggestion, index) => (
              <button
                key={index}
                onClick={() => handleSuggestionClick(suggestion.title)}
                className="w-full text-right px-3 py-2 hover:bg-gray-50 flex items-center justify-between group"
              >
                <span className="text-gray-700">{suggestion.title}</span>
                <span className="text-xs text-gray-400 bg-gray-100 px-2 py-1 rounded">
                  {suggestion.category}
                </span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* البحث الشائع */}
      {showSuggestions && suggestions.length === 0 && query.length >= 2 && !isSearching && (
        <div className="absolute top-full mt-2 w-full bg-white rounded-lg shadow-lg border overflow-hidden z-50">
          <div className="p-4 text-center text-gray-500">
            لا توجد اقتراحات. اضغط Enter للبحث عن "{query}"
          </div>
        </div>
      )}
    </div>
  );
}
```

