```tsx
"use client";
import { useState, useEffect } from "react";
import { analyzePerformance } from "../actions";
import { Zap, AlertTriangle, CheckCircle, Loader2, ArrowUp, ArrowDown } from "lucide-react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Progress } from "@/components/ui/progress";
import { toast } from "sonner";

interface PerformanceIssue {
  id: string;
  type: 'critical' | 'warning' | 'info';
  title: string;
  description: string;
  solution: string;
  impact: number;
}

export default function PerformanceAnalyzer() {
  const [analyzing, setAnalyzing] = useState(false);
  const [score, setScore] = useState(0);
  const [issues, setIssues] = useState<PerformanceIssue[]>([]);
  const [analyzed, setAnalyzed] = useState(false);

  const handleAnalyze = async () => {
    setAnalyzing(true);
    try {
      const result = await analyzePerformance();
      setScore(result.score);
      setIssues(result.issues);
      setAnalyzed(true);
      toast.success("تم تحليل الأداء");
    } catch (error) {
      toast.error("فشل التحليل");
    } finally {
      setAnalyzing(false);
    }
  };

  const getScoreColor = (score: number) => {
    if (score >= 90) return 'text-green-600';
    if (score >= 70) return 'text-yellow-600';
    return 'text-red-600';
  };

  const getIssueIcon = (type: string) => {
    switch (type) {
      case 'critical': return <AlertTriangle className="h-5 w-5 text-red-600" />;
      case 'warning': return <AlertTriangle className="h-5 w-5 text-yellow-600" />;
      case 'info': return <CheckCircle className="h-5 w-5 text-blue-600" />;
    }
  };

  return (
