## 🧠 المرحلة 2: إعداد خدمة الذكاء الاصطناعي المركزية

ملف: `lib/ai/openai-service.ts`

```typescript
import OpenAI from 'openai';
import { getServerSession } from 'next-auth';

// تهيئة عميل OpenAI
const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
  organization: process.env.OPENAI_ORG_ID,
});

// إعدادات الافتراضية
const DEFAULT_CONFIG = {
  model: process.env.OPENAI_MODEL || 'gpt-4-turbo-preview',
  maxTokens: parseInt(process.env.AI_MAX_TOKENS || '4096'),
  temperature: parseFloat(process.env.AI_TEMPERATURE || '0.7'),
};

// سياق الموقع (ليفهم AI طبيعة مشروعك)
const SITE_CONTEXT = `
أنت مساعد ذكي متخصص في تطوير مواقع الويب.
الموقع الحالي هو مدونة احترافية مبنية بـ:
- Next.js 14 (App Router)
- TypeScript
- Tailwind CSS
- MongoDB
- NextAuth.js

الميزات الحالية:
- نظام مستخدمين مع صلاحيات
- لوحة تحكم شاملة
- نظام مقالات وتعليقات
- تخزين سحابي
- API موثق

دورك هو مساعدة المطور في:
1. كتابة كود نظيف وآمن
2. حل المشاكل التقنية
3. اقتراح تحسينات
4. تحليل الأداء
5. كتابة الوثائق

استجب باللغة العربية دائماً ما لم يُطلب غير ذلك.
`;

export interface AIMessage {
  role: 'system' | 'user' | 'assistant';
  content: string;
}

export interface AIResponse {
  message: string;
  type: 'text' | 'code' | 'suggestion' | 'analysis';
  tokens?: {
    prompt: number;
    completion: number;
    total: number;
  };
  model?: string;
}

// إرسال رسالة للذكاء الاصطناعي
export async function sendToAI(
  messages: AIMessage[],
  config: Partial<typeof DEFAULT_CONFIG> = {}
): Promise<AIResponse> {
  try {
    const session = await getServerSession();
    if (!session || session.user?.role !== 'admin') {
      throw new Error('غير مصرح - يجب أن تكون مديرًا');
    }

    const finalMessages: AIMessage[] = [
      { role: 'system', content: SITE_CONTEXT },
      ...messages,
    ];

    const completion = await openai.chat.completions.create({
      model: config.model || DEFAULT_CONFIG.model,
      messages: finalMessages as any,
      max_tokens: config.maxTokens || DEFAULT_CONFIG.maxTokens,
      temperature: config.temperature || DEFAULT_CONFIG.temperature,
    });

    const content = completion.choices[0]?.message?.content || '';

    // تحديد نوع الاستجابة
    let type: AIResponse['type'] = 'text';
    if (content.includes('```')) type = 'code';
    if (content.includes('اقتراح') || content.includes('توصية')) type = 'suggestion';
    if (content.includes('تحليل') || content.includes('نتيجة')) type = 'analysis';

    return {
      message: content,
      type,
      tokens: {
        prompt: completion.usage?.prompt_tokens || 0,
        completion: completion.usage?.completion_tokens || 0,
        total: completion.usage?.total_tokens || 0,
      },
      model: completion.model,
    };
  } catch (error: any) {
    console.error('OpenAI API Error:', error);
    throw new Error(`فشل الاتصال بالذكاء الاصطناعي: ${error.message}`);
  }
}

