```typescript
"use server";
import { getServerSession } from "next-auth";
import { 
  sendToAI, 
  generateCodeWithAI, 
  analyzePerformanceWithAI, 
  suggestFeaturesWithAI,
  securityAuditWithAI,
  optimizeSEOWithAI,
  trackAIUsage,
  AIMessage 
} from "@/lib/ai/openai-service";
