export async function sendAIMessage(message: string, conversationHistory?: AIMessage[]) {
  const session = await getServerSession();
  if (!session || session.user?.role !== "admin") {
    throw new Error("غير مصرح");
  }

  const messages: AIMessage[] = [
    ...(conversationHistory || []).slice(-10), // آخر 10 رسائل فقط
    { role: 'user', content: message },
  ];

  const response = await sendToAI(messages);

  // تتبع الاستخدام
  if (response.tokens) {
    await trackAIUsage(session.user.id || 'unknown', response.tokens, 'chat');
  }

  return response;
}

