## 3️⃣ مكتبة الوسائط المتقدمة (Media Library)

**ملف: `app/dashboard/media/page.tsx`**
```tsx
"use client";
import { useState, useCallback } from "react";
import { useDropzone } from "react-dropzone";
import { uploadFile, getMediaFiles, deleteFile } from "./actions";
import { toast } from "sonner";
import { Image, File, Trash2, Download, Copy } from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import Image from "next/image";

export default function MediaLibrary() {
  const [files, setFiles] = useState<any[]>([]);
  const [uploading, setUploading] = useState(false);

  const onDrop = useCallback(async (acceptedFiles: File[]) => {
    setUploading(true);
    try {
      for (const file of acceptedFiles) {
        const formData = new FormData();
        formData.append('file', file);

        const result = await uploadFile(formData);
        if (result.success) {
          toast.success(`تم رفع ${file.name}`);
          setFiles(prev => [result.file, ...prev]);
        } else {
          toast.error(`فشل رفع ${file.name}`);
        }
      }
    } catch (error) {
      toast.error('حدث خطأ أثناء الرفع');
    } finally {
      setUploading(false);
    }
  }, []);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: {
      'image/*': ['.png', '.jpg', '.jpeg', '.gif', '.webp'],
      'application/pdf': ['.pdf'],
    },
    maxFiles: 10,
    maxSize: 10 * 1024 * 1024, // 10MB
  });

  const handleCopyUrl = (url: string) => {
    navigator.clipboard.writeText(url);
    toast.success('تم نسخ الرابط');
  };

  const handleDelete = async (fileId: string) => {
    if (confirm('هل أنت متأكد من حذف هذا الملف؟')) {
      await deleteFile(fileId);
      setFiles(prev => prev.filter(f => f._id !== fileId));
      toast.success('تم حذف الملف');
    }
  };

  return (
    <div className="space-y-6" dir="rtl">
      <div>
        <h1 className="text-3xl font-bold text-gray-900">مكتبة الوسائط</h1>
        <p className="text-gray-500 mt-1">إدارة الصور والملفات</p>
      </div>

      {/* منطقة الرفع */}
      <div
        {...getRootProps()}
        className={`border-2 border-dashed rounded-lg p-10 text-center cursor-pointer transition
          ${isDragActive ? 'border-blue-500 bg-blue-50' : 'border-gray-300 hover:border-gray-400'}
          ${uploading ? 'opacity-50 pointer-events-none' : ''}`}
      >
        <input {...getInputProps()} />
        <Image className="h-12 w-12 mx-auto text-gray-400 mb-4" />
        {isDragActive ? (
          <p className="text-blue-600 font-medium">أفلت الملفات هنا...</p>
        ) : (
          <>
            <p className="text-gray-600 font-medium">اسحب وأفلت الملفات هنا، أو انقر للاختيار</p>
            <p className="text-sm text-gray-400 mt-2">PNG, JPG, GIF, WebP, PDF (حد أقصى 10MB)</p>
          </>
        )}
        {uploading && <p className="text-blue-600 mt-4">جاري الرفع...</p>}
      </div>

      {/* شبكة الملفات */}
      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
        {files.map((file) => (
          <Card key={file._id} className="group relative overflow-hidden">
            <CardContent className="p-0">
              <div className="aspect-square relative">
                {file.type.startsWith('image/') ? (
                  <Image
                    src={file.url}
                    alt={file.name}
                    fill
                    className="object-cover"
                  />
                ) : (
                  <div className="h-full w-full bg-gray-100 flex items-center justify-center">
                    <File className="h-12 w-12 text-gray-400" />
                  </div>
                )}

                {/* أزرار الإجراءات */}
                <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition flex items-center justify-center gap-2">
                  <Button
                    size="icon"
                    variant="secondary"
                    onClick={() => handleCopyUrl(file.url)}
                  >
                    <Copy className="h-4 w-4" />
                  </Button>
                  <Button
                    size="icon"
                    variant="destructive"
                    onClick={() => handleDelete(file._id)}
                  >
                    <Trash2 className="h-4 w-4" />
                  </Button>
                </div>
              </div>
              <div className="p-2">
                <p className="text-xs truncate" title={file.name}>{file.name}</p>
                <p className="text-xs text-gray-400">{(file.size / 1024).toFixed(1)} KB</p>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
}
