"use client";
import { useState } from "react";
import { createBackup, restoreBackup, getBackups } from "./actions";
import { toast } from "sonner";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Download, Upload, Database, Clock } from "lucide-react";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";

export default function BackupPage() {
  const [backups, setBackups] = useState<any[]>([]);
  const [creating, setCreating] = useState(false);
  const [restoring, setRestoring] = useState(false);

  const handleCreateBackup = async () => {
    setCreating(true);
    try {
      const result = await createBackup();
      if (result.success) {
        toast.success('تم إنشاء نسخة احتياطية');
        setBackups(prev => [result.backup, ...prev]);
      } else {
        toast.error('فشل إنشاء النسخة');
      }
    } catch (error) {
      toast.error('حدث خطأ');
    } finally {
      setCreating(false);
    }
  };

  const handleRestore = async (backupId: string) => {
    if (confirm('تحذير: سيتم استبدال جميع البيانات الحالية. هل أنت متأكد؟')) {
      setRestoring(true);
      try {
        await restoreBackup(backupId);
        toast.success('تم استعادة النسخة بنجاح');
      } catch (error) {
        toast.error('فشل الاستعادة');
      } finally {
        setRestoring(false);
      }
    }
  };

  const handleDownload = async (backupId: string) => {
    window.open(`/api/backup/download/${backupId}`, '_blank');
    toast.info('جاري تحميل النسخة');
  };

  return (
    <div className="space-y-6" dir="rtl">
      <div>
        <h1 className="text-3xl font-bold text-gray-900">النسخ الاحتياطي</h1>
