              إنشاء نسخة جديدة
            </CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-sm text-gray-500 mb-4">
              إنشاء نسخة احتياطية كاملة من قاعدة البيانات والمقالات والمستخدمين
            </p>
            <Button onClick={handleCreateBackup} disabled={creating} className="w-full">
              <Download className="ml-2 h-4 w-4" />
              {creating ? 'جاري الإنشاء...' : 'إنشاء نسخة احتياطية'}
            </Button>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Upload className="h-5 w-5" />
              استعادة نسخة
            </CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-sm text-gray-500 mb-4">
              استعادة بيانات الموقع من نسخة احتياطية سابقة
            </p>
            <input
              type="file"
              accept=".json"
              className="block w-full text-sm text-gray-500
                file:ml-4 file:py-2 file:px-4
                file:rounded-md file:border-0
