      <Card>
        <CardHeader>
          <CardTitle>النسخ الاحتياطية السابقة</CardTitle>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>التاريخ</TableHead>
                <TableHead>الحجم</TableHead>
