### مكون عرض التعليقات للزوار `components/CommentsSection.tsx`

```tsx
"use client";
import { useState } from "react";
import { useSession } from "next-auth/react";
import { createComment, likeComment, reportComment } from "@/app/actions/comments";
import { toast } from "sonner";
import { Heart, Flag, Reply, Send } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import Image from "next/image";

interface Comment {
  _id: string;
  authorName: string;
  authorImage?: string;
  content: string;
  createdAt: string;
  likes: string[];
  replies?: Comment[];
}

export default function CommentsSection({ 
  postId, 
  comments 
}: { 
  postId: string; 
  comments: Comment[] 
}) {
  const {  session } = useSession();
  const [content, setContent] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [replyingTo, setReplyingTo] = useState<string | null>(null);
  const [replyContent, setReplyContent] = useState("");

  const handleSubmit = async (e: React.FormEvent, parentId?: string) => {
    e.preventDefault();
    if (!session) {
      toast.error("يجب تسجيل الدخول للتعليق");
      return;
    }

    setSubmitting(true);
    try {
      await createComment({
        postId,
        content: parentId ? replyContent : content,
        parentComment: parentId || null,
      });
      toast.success("تم إرسال التعليق للمراجعة");
      setContent("");
      setReplyContent("");
      setReplyingTo(null);
    } catch (error) {
      toast.error("فشل إرسال التعليق");
    } finally {
      setSubmitting(false);
    }
  };

  const handleLike = async (commentId: string) => {
    if (!session) {
      toast.error("يجب تسجيل الدخول للإعجاب");
      return;
    }
    await likeComment(commentId);
  };

  const handleReport = async (commentId: string) => {
    if (!session) {
      toast.error("يجب تسجيل الدخول للإبلاغ");
      return;
    }
    await reportComment(commentId, "محتوى غير لائق");
    toast.success("تم إرسال البلاغ");
  };

  return (
    <div className="mt-12 space-y-8">
      <h2 className="text-2xl font-bold">التعليقات ({comments.length})</h2>

      {/* نموذج التعليق */}
      <form onSubmit={(e) => handleSubmit(e)} className="space-y-4">
        <Textarea
          value={content}
          onChange={(e) => setContent(e.target.value)}
          placeholder="اكتب تعليقك هنا..."
          rows={4}
          className="w-full p-4 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
        />
        <Button 
          type="submit" 
          disabled={submitting || !content.trim()}
          className="flex items-center gap-2"
        >
          <Send className="h-4 w-4" />
          {submitting ? "جاري الإرسال..." : "إرسال التعليق"}
        </Button>
      </form>

      {/* قائمة التعليقات */}
      <div className="space-y-6">
        {comments.map((comment) => (
          <div key={comment._id} className="bg-gray-50 p-6 rounded-lg">
            <div className="flex items-start gap-4">
              <div className="h-10 w-10 rounded-full bg-gray-200 overflow-hidden flex-shrink-0">
                {comment.authorImage ? (
                  <Image src={comment.authorImage} alt={comment.authorName} width={40} height={40} className="object-cover" />
                ) : (
                  <div className="h-full w-full flex items-center justify-center text-gray-500">
                    {comment.authorName.charAt(0)}
                  </div>
                )}
              </div>
              <div className="flex-1">
                <div className="flex items-center justify-between">
                  <div>
                    <span className="font-semibold">{comment.authorName}</span>
                    <span className="text-sm text-gray-500 mr-2">
                      {new Date(comment.createdAt).toLocaleDateString('ar-EG')}
                    </span>
                  </div>
                </div>
                <p className="mt-2 text-gray-700">{comment.content}</p>
                <div className="mt-4 flex items-center gap-4">
                  <button
                    onClick={() => handleLike(comment._id)}
                    className="flex items-center gap-1 text-sm text-gray-500 hover:text-red-500"
                  >
                    <Heart className={`h-4 w-4 ${comment.likes.includes(session?.user?.id || '') ? 'fill-red-500 text-red-500' : ''}`} />
                    {comment.likes.length}
                  </button>
                  <button
                    onClick={() => setReplyingTo(comment._id)}
                    className="flex items-center gap-1 text-sm text-gray-500 hover:text-blue-500"
                  >
                    <Reply className="h-4 w-4" />
                    رد
                  </button>
                  <button
                    onClick={() => handleReport(comment._id)}
                    className="flex items-center gap-1 text-sm text-gray-500 hover:text-orange-500"
                  >
                    <Flag className="h-4 w-4" />
                    إبلاغ
                  </button>
                </div>

                {/* نموذج الرد */}
                {replyingTo === comment._id && (
                  <form onSubmit={(e) => handleSubmit(e, comment._id)} className="mt-4 space-y-2">
                    <Textarea
                      value={replyContent}
                      onChange={(e) => setReplyContent(e.target.value)}
                      placeholder="اكتب ردك..."
                      rows={2}
                      className="w-full p-3 border rounded-lg text-sm"
                    />
                    <div className="flex gap-2">
                      <Button type="submit" size="sm" disabled={submitting}>
                        إرسال الرد
                      </Button>
                      <Button 
                        type="button" 
                        variant="ghost" 
                        size="sm"
                        onClick={() => setReplyingTo(null)}
                      >
                        إلغاء
                      </Button>
                    </div>
                  </form>
                )}

                {/* الردود */}
                {comment.replies && comment.replies.length > 0 && (
                  <div className="mt-4 mr-8 space-y-4 border-r-2 border-gray-200 pr-4">
                    {comment.replies.map((reply) => (
