### نموذج رفع الملفات المتقدم `components/AdvancedFileUpload.tsx`

```tsx
"use client";
import { useState, useCallback } from "react";
import { useDropzone } from "react-dropzone";
import { uploadFile, optimizeImage } from "@/lib/storage";
import { toast } from "sonner";
import { Upload, Image, File, X, Check, Loader2 } from "lucide-react";
import { Progress } from "@/components/ui/progress";
import { Button } from "@/components/ui/button";
import Image from "next/image";

interface UploadedFile {
  url: string;
  name: string;
  size: number;
  type: string;
  optimized?: boolean;
}

export default function AdvancedFileUpload({
  onFilesUploaded,
  maxFiles = 10,
  maxSize = 10 * 1024 * 1024,
  accept = { 'image/*': ['.png', '.jpg', '.jpeg', '.gif', '.webp'] },
  optimize = true,
}) {
  const [files, setFiles] = useState<UploadedFile[]>([]);
  const [uploading, setUploading] = useState(false);
  const [progress, setProgress] = useState(0);

  const onDrop = useCallback(async (acceptedFiles: File[]) => {
    setUploading(true);
    setProgress(0);

    try {
      for (let i = 0; i < acceptedFiles.length; i++) {
        const file = acceptedFiles[i];
        const currentProgress = ((i + 1) / acceptedFiles.length) * 100;
        setProgress(currentProgress);

        let result;
        if (optimize && file.type.startsWith('image/')) {
          result = await optimizeImage(file);
        } else {
          result = await uploadFile(file);
        }

        if (result.success) {
          setFiles(prev => [...prev, {
            url: result.url,
            name: file.name,
            size: file.size,
            type: file.type,
            optimized: result.optimized || false,
          }]);
          toast.success(`تم رفع ${file.name}`);
        } else {
          toast.error(`فشل رفع ${file.name}`);
        }
      }

      onFilesUploaded?.(files);
    } catch (error) {
      toast.error('حدث خطأ أثناء الرفع');
    } finally {
      setUploading(false);
      setProgress(0);
    }
  }, [onFilesUploaded, files, optimize]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept,
    maxFiles,
    maxSize,
  });

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const formatSize = (bytes: number) => {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  };

  return (
    <div className="space-y-4">
      <div
        {...getRootProps()}
        className={`border-2 border-dashed rounded-lg p-8 text-center cursor-pointer transition
          ${isDragActive ? 'border-blue-500 bg-blue-50' : 'border-gray-300 hover:border-gray-400'}
          ${uploading ? 'opacity-50 pointer-events-none' : ''}`}
      >
        <input {...getInputProps()} />
        <Upload className="h-12 w-12 mx-auto text-gray-400 mb-4" />
        {isDragActive ? (
          <p className="text-blue-600 font-medium">أفلت الملفات هنا...</p>
        ) : (
          <>
            <p className="text-gray-600 font-medium">اسحب وأفلت الملفات، أو انقر للاختيار</p>
            <p className="text-sm text-gray-400 mt-2">
              حد أقصى {maxFiles} ملفات، {formatSize(maxSize)} لكل ملف
            </p>
          </>
        )}
        {uploading && (
          <div className="mt-4">
            <Progress value={progress} className="w-full" />
            <p className="text-sm text-gray-500 mt-2">جاري الرفع... {Math.round(progress)}%</p>
          </div>
        )}
      </div>

      {/* قائمة الملفات المرفوعة */}
      {files.length > 0 && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {files.map((file, index) => (
            <div key={index} className="relative group bg-gray-50 rounded-lg overflow-hidden border">
              {file.type.startsWith('image/') ? (
                <div className="aspect-square relative">
                  <Image
                    src={file.url}
                    alt={file.name}
                    fill
                    className="object-cover"
                  />
                </div>
              ) : (
                <div className="aspect-square flex items-center justify-center bg-gray-100">
                  <File className="h-12 w-12 text-gray-400" />
                </div>
              )}

              {/* معلومات الملف */}
              <div className="absolute inset-0 bg-black/70 opacity-0 group-hover:opacity-100 transition flex flex-col items-center justify-center p-2">
                <p className="text-white text-xs text-center truncate w-full mb-2">{file.name}</p>
                <p className="text-gray-300 text-xs">{formatSize(file.size)}</p>
                {file.optimized && (
                  <span className="text-green-400 text-xs flex items-center gap-1 mt-1">
                    <Check className="h-3 w-3" /> محسّن
                  </span>
                )}
                <Button
                  size="icon"
                  variant="destructive"
                  className="mt-2"
                  onClick={() => removeFile(index)}
                >
                  <X className="h-4 w-4" />
                </Button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
