import { NextResponse } from 'next/server';
import { connectToDatabase } from '@/lib/mongodb';
import Post from '@/models/Post';

export async function GET() {
  await connectToDatabase();

  const posts = await Post.find({ published: true })
    .sort({ createdAt: -1 })
    .limit(20)
    .populate('author', 'name');

  const baseUrl = process.env.NEXT_PUBLIC_URL || 'http://localhost:3000';

  const rss = `<?xml version="1.0" encoding="UTF-8"?>
<rss version="2.0" xmlns:atom="http://www.w3.org/2005/Atom">
  <channel>
    <title>مدونتي</title>
    <link>${baseUrl}</link>
    <description>أحدث المقالات من مدونتي</description>
    <language>ar</language>
    <lastBuildDate>${new Date().toUTCString()}</lastBuildDate>
    <atom:link href="${baseUrl}/rss.xml" rel="self" type="application/rss+xml"/>
    ${posts.map((post) => `
      <item>
        <title><![CDATA[${post.title}]]></title>
        <link>${baseUrl}/posts/${post._id}</link>
        <guid>${baseUrl}/posts/${post._id}</guid>
        <description><![CDATA[${post.content?.substring(0, 500)}...]]></description>
        <pubDate>${new Date(post.createdAt).toUTCString()}</pubDate>
        <author>${post.author?.name || 'غير معروف'}</author>
      </item>
    `).join('')}
  </channel>
</rss>`;

  return new NextResponse(rss, {
    headers: {
      'Content-Type': 'application/xml',
      'Cache-Control': 's-maxage=3600, stale-while-revalidate',
    },
  });
}
