import { describe, it, expect } from '@jest/globals';

// دوال مساعدة للاختبار
function formatDate(date: Date): string {
  return date.toLocaleDateString('ar-EG');
}

function truncateText(text: string, maxLength: number): string {
  if (text.length <= maxLength) return text;
  return text.substring(0, maxLength) + '...';
}

function validateEmail(email: string): boolean {
  const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return regex.test(email);
}

describe('Utility Functions', () => {
  describe('formatDate', () => {
    it('should format date correctly', () => {
      const date = new Date('2024-01-15');
      expect(formatDate(date)).toContain('2024');
    });
  });

  describe('truncateText', () => {
    it('should truncate text when exceeding max length', () => {
      const text = 'هذا نص طويل جداً يحتاج إلى اختصار';
      expect(truncateText(text, 10)).toHaveLength(13); // 10 + ...
    });

    it('should not truncate text when within max length', () => {
      const text = 'نص قصير';
      expect(truncateText(text, 50)).toBe(text);
    });
  });

  describe('validateEmail', () => {
    it('should validate correct email', () => {
      expect(validateEmail('test@example.com')).toBe(true);
    });

    it('should reject invalid email', () => {
      expect(validateEmail('invalid-email')).toBe(false);
      expect(validateEmail('')).toBe(false);
    });
  });
});
```

