### 2️⃣ المساعد الذكي للمحادثة (AI Chat Assistant)
ملف: `app/dashboard/ai-dev-center/components/AIChatAssistant.tsx`

```tsx
"use client";
import { useState, useRef, useEffect } from "react";
import { sendAIMessage } from "../actions";
import { Send, Bot, User, Loader2, Code, Lightbulb, Bug } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Card } from "@/components/ui/card";

interface Message {
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
  type?: 'text' | 'code' | 'suggestion';
}

export default function AIChatAssistant() {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'assistant',
      content: 'مرحباً! أنا مساعدك الذكي لتطوير الموقع. يمكنني مساعدتك في:\n• كتابة كود جديد\n• حل المشاكل التقنية\n• اقتراح تحسينات\n• تحليل الأداء\n\nكيف يمكنني مساعدتك اليوم؟',
      timestamp: new Date(),
    },
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || loading) return;

    const userMessage: Message = {
      role: 'user',
      content: input,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInput("");
    setLoading(true);

    try {
      const response = await sendAIMessage(input);

      const aiMessage: Message = {
        role: 'assistant',
        content: response.message,
        timestamp: new Date(),
        type: response.type,
      };

      setMessages(prev => [...prev, aiMessage]);
    } catch (error) {
      setMessages(prev => [...prev, {
        role: 'assistant',
        content: 'عذراً، حدث خطأ. يرجى المحاولة مرة أخرى.',
        timestamp: new Date(),
      }]);
    } finally {
      setLoading(false);
    }
  };

  const quickActions = [
    { icon: Code, label: 'اكتب كود', query: 'اكتب لي كود لـ' },
    { icon: Lightbulb, label: 'اقترح ميزة', query: 'اقترح ميزات لـ' },
    { icon: Bug, label: 'حل مشكلة', query: 'لدي مشكلة في' },
  ];

  return (
    <div className="space-y-4">
      {/* رسائل المحادثة */}
      <div className="h-96 overflow-y-auto space-y-4 p-4 bg-gray-50 rounded-lg">
        {messages.map((message, index) => (
          <div
            key={index}
            className={`flex gap-3 ${message.role === 'user' ? 'flex-row-reverse' : ''}`}
          >
            <div className={`p-2 rounded-full ${
              message.role === 'user' ? 'bg-blue-600' : 'bg-green-600'
            }`}>
              {message.role === 'user' ? (
                <User className="h-5 w-5 text-white" />
              ) : (
                <Bot className="h-5 w-5 text-white" />
              )}
            </div>
            <Card className={`p-4 max-w-2xl ${
              message.role === 'user' ? 'bg-blue-50' : 'bg-white'
            }`}>
              <div className="whitespace-pre-wrap text-gray-800">{message.content}</div>
              <div className="text-xs text-gray-400 mt-2">
                {message.timestamp.toLocaleTimeString('ar-EG')}
              </div>
            </Card>
          </div>
        ))}
        {loading && (
          <div className="flex gap-3">
            <div className="p-2 rounded-full bg-green-600">
              <Bot className="h-5 w-5 text-white" />
            </div>
            <Card className="p-4">
              <Loader2 className="h-5 w-5 animate-spin text-gray-400" />
            </Card>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* إجراءات سريعة */}
      <div className="flex gap-2">
        {quickActions.map((action, index) => (
          <Button
            key={index}
            variant="outline"
            size="sm"
            onClick={() => setInput(action.query)}
            className="flex items-center gap-2"
          >
            <action.icon className="h-4 w-4" />
            {action.label}
          </Button>
        ))}
      </div>

      {/* نموذج الإدخال */}
      <form onSubmit={handleSubmit} className="flex gap-2">
        <Textarea
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="اكتب سؤالك أو طلبك هنا..."
          className="flex-1 resize-none"
          rows={3}
          onKeyDown={(e) => {
            if (e.key === 'Enter' && !e.shiftKey) {
              e.preventDefault();
              handleSubmit(e);
            }
          }}
        />
        <Button type="submit" disabled={loading} className="self-end">
          <Send className="h-4 w-4" />
        </Button>
      </form>
    </div>
  );
}
