### 3️⃣ مولد الكود بالذكاء الاصطناعي (AI Code Generator)
ملف: `app/dashboard/ai-dev-center/components/CodeGenerator.tsx`

```tsx
"use client";
import { useState } from "react";
import { generateCode } from "../actions";
import { Code2, Copy, Download, Check, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Card } from "@/components/ui/card";
import { toast } from "sonner";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

export default function CodeGenerator() {
  const [prompt, setPrompt] = useState("");
  const [codeType, setCodeType] = useState("component");
  const [generatedCode, setGeneratedCode] = useState("");
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    setLoading(true);
    try {
      const result = await generateCode(prompt, codeType);
      setGeneratedCode(result.code);
      toast.success("تم توليد الكود بنجاح");
    } catch (error) {
      toast.error("فشل توليد الكود");
    } finally {
      setLoading(false);
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(generatedCode);
    setCopied(true);
    toast.success("تم نسخ الكود");
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = () => {
    const blob = new Blob([generatedCode], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `generated-${codeType}.tsx`;
    a.click();
    toast.success("تم تحميل الملف");
  };

  return (
    <div className="space-y-4">
      <div className="space-y-2">
        <label className="text-sm font-medium">نوع الكود</label>
        <Select value={codeType} onValueChange={setCodeType}>
          <SelectTrigger>
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="component">مكون React</SelectItem>
            <SelectItem value="page">صفحة كاملة</SelectItem>
            <SelectItem value="api">API Route</SelectItem>
            <SelectItem value="model">Database Model</SelectItem>
            <SelectItem value="function">دالة مساعدة</SelectItem>
          </SelectContent>
        </Select>
      </div>

      <div className="space-y-2">
        <label className="text-sm font-medium">وصف الميزة المطلوبة</label>
        <Textarea
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
          placeholder="مثال: أنشئ مكون بطاقة مقال يعرض الصورة والعنوان والتاريخ..."
          rows={4}
        />
      </div>

      <Button onClick={handleGenerate} disabled={loading} className="w-full">
        {loading ? (
          <Loader2 className="h-4 w-4 animate-spin ml-2" />
        ) : (
          <Code2 className="h-4 w-4 ml-2" />
        )}
        توليد الكود
      </Button>

      {generatedCode && (
        <Card className="overflow-hidden">
          <div className="flex justify-between items-center p-3 border-b bg-gray-50">
            <span className="text-sm font-medium text-gray-600">الكود المولد</span>
            <div className="flex gap-2">
              <Button size="sm" variant="outline" onClick={handleCopy}>
                {copied ? <Check className="h-4 w-4" /> : <Copy className="h-4 w-4" />}
              </Button>
              <Button size="sm" variant="outline" onClick={handleDownload}>
                <Download className="h-4 w-4" />
              </Button>
            </div>
          </div>
          <pre className="p-4 bg-gray-900 text-green-400 overflow-x-auto text-sm" dir="ltr">
            <code>{generatedCode}</code>
          </pre>
        </Card>
      )}
    </div>
  );
}
