```tsx
"use client";
import { useState, useEffect } from "react";
import { analyzePerformance } from "../actions";
import { Zap, AlertTriangle, CheckCircle, Loader2, ArrowUp, ArrowDown } from "lucide-react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Progress } from "@/components/ui/progress";
import { toast } from "sonner";

interface PerformanceIssue {
  id: string;
  type: 'critical' | 'warning' | 'info';
  title: string;
  description: string;
  solution: string;
  impact: number;
}

export default function PerformanceAnalyzer() {
  const [analyzing, setAnalyzing] = useState(false);
  const [score, setScore] = useState(0);
  const [issues, setIssues] = useState<PerformanceIssue[]>([]);
  const [analyzed, setAnalyzed] = useState(false);

  const handleAnalyze = async () => {
    setAnalyzing(true);
    try {
      const result = await analyzePerformance();
      setScore(result.score);
      setIssues(result.issues);
      setAnalyzed(true);
      toast.success("تم تحليل الأداء");
    } catch (error) {
      toast.error("فشل التحليل");
    } finally {
      setAnalyzing(false);
    }
  };

  const getScoreColor = (score: number) => {
    if (score >= 90) return 'text-green-600';
    if (score >= 70) return 'text-yellow-600';
    return 'text-red-600';
  };

  const getIssueIcon = (type: string) => {
    switch (type) {
      case 'critical': return <AlertTriangle className="h-5 w-5 text-red-600" />;
      case 'warning': return <AlertTriangle className="h-5 w-5 text-yellow-600" />;
      case 'info': return <CheckCircle className="h-5 w-5 text-blue-600" />;
    }
  };

  return (
    <div className="space-y-6">
      {/* درجة الأداء */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className={`text-5xl font-bold ${getScoreColor(score)}`}>
            {analyzed ? score : '--'}
          </div>
          <div>
            <p className="text-sm text-gray-500">درجة الأداء العامة</p>
            <Progress value={score} className="w-48" />
          </div>
        </div>
        <Button onClick={handleAnalyze} disabled={analyzing}>
          {analyzing ? (
            <Loader2 className="h-4 w-4 animate-spin ml-2" />
          ) : (
            <Zap className="h-4 w-4 ml-2" />
          )}
          {analyzing ? 'جاري التحليل...' : analyzed ? 'إعادة التحليل' : 'تحليل الأداء'}
        </Button>
      </div>

      {/* المشاكل والتوصيات */}
      {analyzed && issues.length > 0 && (
        <div className="space-y-3">
          <h3 className="font-semibold flex items-center gap-2">
            <AlertTriangle className="h-5 w-5 text-orange-600" />
            التوصيات ({issues.length})
          </h3>
          {issues.map((issue) => (
            <Card key={issue.id} className="p-4 border-r-4 border-r-orange-500">
              <div className="flex items-start gap-3">
                {getIssueIcon(issue.type)}
                <div className="flex-1">
                  <div className="flex items-center justify-between">
                    <h4 className="font-medium">{issue.title}</h4>
                    <span className="text-xs text-gray-500">
                      التأثير: {issue.impact}%
                    </span>
                  </div>
                  <p className="text-sm text-gray-600 mt-1">{issue.description}</p>
                  <div className="mt-3 p-3 bg-blue-50 rounded-lg">
                    <p className="text-sm text-blue-800">
                      <strong>الحل:</strong> {issue.solution}
                    </p>
                  </div>
                </div>
              </div>
            </Card>
          ))}
        </div>
      )}

      {analyzed && issues.length === 0 && (
        <Card className="p-6 text-center bg-green-50 border-green-200">
          <CheckCircle className="h-12 w-12 text-green-600 mx-auto mb-4" />
          <h3 className="text-xl font-bold text-green-800">أداء ممتاز!</h3>
          <p className="text-green-600">لا توجد مشاكل أداء حالية</p>
        </Card>
      )}
    </div>
  );
}
