"use server";
import { getServerSession } from "next-auth";

// محاكاة لخدمة الذكاء الاصطناعي (يمكن استبدالها بـ OpenAI API)
const AI_API_KEY = process.env.OPENAI_API_KEY;

export async function sendAIMessage(message: string) {
  const session = await getServerSession();
  if (!session || session.user?.role !== "admin") {
    throw new Error("غير مصرح");
  }

  // هنا يتم الاتصال بـ OpenAI أو أي خدمة AI
  // للتوضيح سنستخدم ردوداً مبرمجة مسبقاً
  const responses: Record<string, string> = {
    'كود': 'لتوليد كود، يرجى استخدام أداة "مولد الكود" في هذه الصفحة.',
    'مشكلة': 'لحل المشاكل، استخدم أداة "كشف الأخطاء" أو صف المشكلة بالتفصيل.',
    'أداء': 'لتحليل الأداء، استخدم أداة "تحليل الأداء الذكي".',
    'ميزة': 'لاقتراح الميزات، راجع قسم "اقتراحات الميزات".',
  };

  let response = 'شكراً لسؤالك. يمكنني مساعدتك في تطوير موقعك بعدة طرق:';
  for (const [key, value] of Object.entries(responses)) {
    if (message.includes(key)) {
      response = value;
      break;
    }
  }

  return {
    message: response,
    type: 'text',
  };
}

export async function generateCode(prompt: string, type: string) {
  const session = await getServerSession();
  if (!session || session.user?.role !== "admin") {
    throw new Error("غير مصرح");
  }

  // مثال على كود مولد (في الواقع يتم الاتصال بـ OpenAI)
  const codeExamples: Record<string, string> = {
    'component': `// مكون React
export default function GeneratedComponent() {
  return (
    <div className="p-4 bg-white rounded-lg shadow">
      <h2 className="text-xl font-bold">مكون مولد</h2>
      <p>هذا مكون تم توليده بالذكاء الاصطناعي</p>
    </div>
  );
}`,
    'page': `// صفحة Next.js
export default function GeneratedPage() {
  return (
    <div className="min-h-screen p-8">
      <h1 className="text-3xl font-bold">صفحة جديدة</h1>
      <p>تم إنشاء هذه الصفحة بالذكاء الاصطناعي</p>
    </div>
  );
}`,
    'api': `// API Route
import { NextResponse } from 'next/server';

export async function GET() {
  return NextResponse.json({ message: 'API جاهز' });
}`,
    'model': `// MongoDB Model
import mongoose from 'mongoose';

const Schema = new mongoose.Schema({
  name: String,
  createdAt: { type: Date, default: Date.now }
});

export default mongoose.models.Model || mongoose.model('Model', Schema);`,
  };

  return {
    code: codeExamples[type] || codeExamples['component'],
  };
}

export async function getFeatureSuggestions() {
  const session = await getServerSession();
  if (!session || session.user?.role !== "admin") {
    throw new Error("غير مصرح");
  }

  // اقتراحات مبرمجة مسبقاً (يمكن استبدالها بـ AI)
  return {
    features: [
      {
