ملف: `models/AITokenUsage.ts`

```typescript
import mongoose from 'mongoose';

const AITokenUsageSchema = new mongoose.Schema({
  userId: { type: String, required: true, index: true },
  endpoint: { 
    type: String, 
    required: true,
    enum: ['chat', 'code-generation', 'feature-suggestions', 'performance-analysis', 'security-audit', 'seo-optimization']
  },
  tokens: {
    prompt: { type: Number, required: true },
    completion: { type: Number, required: true },
    total: { type: Number, required: true },
  },
  cost: { type: Number, required: true }, // بالدولار
  model: { type: String, default: 'gpt-4-turbo' },
  createdAt: { type: Date, default: Date.now },
}, { timestamps: true });

// حساب التكلفة تلقائياً قبل الحفظ
AITokenUsageSchema.pre('save', function(next) {
  const pricing = {
    'gpt-4-turbo': { prompt: 0.01, completion: 0.03 }, // لكل 1K tokens
    'gpt-4': { prompt: 0.03, completion: 0.06 },
    'gpt-3.5-turbo': { prompt: 0.0005, completion: 0.0015 },
  };

  const modelPricing = pricing[this.model as keyof typeof pricing] || pricing['gpt-4-turbo'];
  this.cost = (this.tokens.prompt / 1000) * modelPricing.prompt + 
              (this.tokens.completion / 1000) * modelPricing.completion;

  next();
});

AITokenUsageSchema.index({ createdAt: -1 });
AITokenUsageSchema.index({ userId: 1, createdAt: -1 });

export default mongoose.models.AITokenUsage || mongoose.model('AITokenUsage', AITokenUsageSchema);
```

