## 🔒 المرحلة 5: حماية ومحدودية الاستخدام

ملف: `lib/ai/rate-limiter.ts`

```typescript
import { Ratelimit } from "@upstash/ratelimit";
import { Redis } from "@upstash/redis";

// إعداد Redis للحد من الاستخدام (اختياري - للاستضافة على Vercel)
const redis = process.env.UPSTASH_REDIS_REST_URL 
  ? new Redis({
      url: process.env.UPSTASH_REDIS_REST_URL,
      token: process.env.UPSTASH_REDIS_REST_TOKEN,
    })
  : null;

const ratelimit = redis 
  ? new Ratelimit({
      redis,
      limiter: Ratelimit.slidingWindow(60, "1 h"), // 60 طلب في الساعة
      analytics: true,
    })
  : null;

export async function checkRateLimit(userId: string) {
  if (!ratelimit) return { success: true };

  const { success, limit, reset, remaining } = await ratelimit.limit(userId);

  return {
    success,
    limit,
    reset,
    remaining,
  };
}

// حد أقصى للتokens لكل طلب
export const TOKEN_LIMITS = {
  chat: 4096,
  'code-generation': 8192,
  'feature-suggestions': 4096,
  'performance-analysis': 2048,
  'security-audit': 8192,
  'seo-optimization': 4096,
};
